module top_module(
input  wire clk,
input  wire rst,
output wire [3:0] count
);reg [3:0] obf_counter_reg;

always @(posedge clk or posedge rst)
    if (rst)
        obf_counter_reg <= 4'b0000;
    else
        obf_counter_reg <= obf_counter_reg + 1;

assign count = obf_counter_reg;

endmodule
